sql:
SELECT player_id, SUM(matches_played) AS total_matches_played
FROM player_season_performance
GROUP BY player_id;

SELECT player_id, fitness_test_date, fitness_score
FROM player_fitness
ORDER BY fitness_score DESC;

SELECT player_id, MAX(fitness_test_date) AS latest_test_date
FROM player_fitness
GROUP BY player_id;

SELECT SUM(runs) AS total_runs, MAX(runs) AS highest_score
FROM player_season_performance
WHERE season_id = 1;
